/**
 * @fileoverview Toast events — event binding for individual toast items.
 * @module module/Toast/events
 */

/**
 * Bind close-button click and hover pause/resume events on a toast element.
 *
 * @param {HTMLElement} toastEl — the toast DOM element
 * @param {object} actions — { dismiss, pause, resume }
 * @param {object} config — { closable, pauseOnHover }
 * @returns {AbortController}
 */
export function bindToastEvents(toastEl, actions, config) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    // Close button
    if (config.closable) {
        const closeBtn = toastEl.querySelector('.toast-close');
        if (closeBtn) {
            closeBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                actions.dismiss();
            }, opts);
        }
    }

    // Pause on hover
    if (config.pauseOnHover) {
        toastEl.addEventListener('mouseenter', () => actions.pause(), opts);
        toastEl.addEventListener('mouseleave', () => actions.resume(), opts);
    }

    return ac;
}
