/**
 * @fileoverview Toast barrel — re-exports from modular implementation.
 * Kept at module root for backward compatibility with razyui.load().
 *
 * @module module/Toast
 */
import { default as razyui } from '../index.js';
import { ToastDef as DEF } from './Toast.def.js';
import Toast from './Toast/index.js';

// Register on the global razyui object
razyui.Toast = Toast;

// Register with JIT compiler if available
if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

// Custom Element registration
export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Toast);
}

export default Toast;

export const stylesheet = null;
